const messages = $.steps.searchEmails.response.messages || [];
const ids = messages.map(m => m.id).filter(Boolean).slice(0, 5);
return { messageIds: ids, count: ids.length };

const iterations = $.steps.fetchMessages.response.iterations || [];
const emails = [];
iterations.forEach((iter) => {
  const msg = (iter.getMessage && iter.getMessage.response) ? iter.getMessage.response : {};
  const headers = (msg.payload && msg.payload.headers) || [];
  const subject = (headers.find(h => h.name === 'Subject') || {}).value || 'No Subject';
  const from = (headers.find(h => h.name === 'From') || {}).value || 'Unknown';
  const date = (headers.find(h => h.name === 'Date') || {}).value || '';
  const parts = (msg.payload && msg.payload.parts) || [];
  const pdfAttachments = [];
  parts.forEach(p => {
    if (p.filename && p.filename.toLowerCase().endsWith('.pdf')) {
      pdfAttachments.push({ filename: p.filename, mimeType: p.mimeType || 'application/pdf', size: p.body ? p.body.size : 0 });
    }
  });
  if (pdfAttachments.length > 0) {
    emails.push({ subject, from, date, attachments: pdfAttachments, snippet: msg.snippet || '' });
  }
});
let emailsText = '';
emails.forEach((e, i) => {
  emailsText += (i+1) + '. Subject: ' + e.subject + '\n';
  emailsText += '   From: ' + e.from + '\n';
  emailsText += '   Date: ' + e.date + '\n';
  emailsText += '   Snippet: ' + e.snippet + '\n';
  emailsText += '   PDF Attachments: ' + e.attachments.map(a => a.filename + ' (' + Math.round(a.size/1024) + 'KB)').join(', ') + '\n\n';
});
return { emails, emailsText, pdfCount: emails.reduce((s, e) => s + e.attachments.length, 0) };

const prompt = `You are a document analysis assistant. Summarize the following emails that contain PDF attachments found in a Gmail inbox.

EMAILS WITH PDF ATTACHMENTS:
${$.steps.extractPdfInfo.output.emailsText}

Total PDFs found: ${$.steps.extractPdfInfo.output.pdfCount}

Provide:
1. A summary of what types of PDFs were found (invoices, reports, contracts, etc.) based on email subjects and context
2. Group the PDFs by category/type
3. Highlight any that might need urgent attention
4. Recommendations for organizing these documents

Return ONLY valid JSON:
{
  "summary": "Overview of PDFs found",
  "categories": [
    { "category": "Category name", "count": 1, "files": ["filename.pdf"], "notes": "Brief note" }
  ],
  "urgent_items": ["Any items needing immediate attention"],
  "recommendations": ["Organization recommendations"]
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, categories: [], urgent_items: [], recommendations: [] }; }

const ai = $.steps.parseAI.output || {};
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'PDF Attachment Summary' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.summary || 'No PDFs analyzed.' } });
blocks.push({ type: 'divider' });
if (ai.categories && ai.categories.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Document Categories*' } });
  ai.categories.forEach(c => {
    let catText = '*' + c.category + '* (' + c.count + ' files)\n';
    if (c.files) catText += c.files.join(', ') + '\n';
    if (c.notes) catText += '_' + c.notes + '_';
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: catText.slice(0, 1900) } });
  });
  blocks.push({ type: 'divider' });
}
if (ai.urgent_items && ai.urgent_items.length > 0) {
  let urgentText = '*:rotating_light: Urgent Items*\n';
  ai.urgent_items.forEach((u, i) => { urgentText += (i+1) + '. ' + u + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: urgentText } });
  blocks.push({ type: 'divider' });
}
if (ai.recommendations && ai.recommendations.length > 0) {
  let recsText = '*Recommendations*\n';
  ai.recommendations.forEach((r, i) => { recsText += (i+1) + '. ' + r + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: recsText } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Total PDFs found: ' + $.steps.extractPdfInfo.output.pdfCount }] });
return { blocks, fallback: 'PDF Summary: ' + $.steps.extractPdfInfo.output.pdfCount + ' PDFs found in Gmail' };
